import{_ as i}from"./plugin-vue_export-helper-c27b6911.js";import{r,o as n,c as d,a as e,b as t,d as l,e as h}from"./app-1a02a24b.js";const o={},s=e("h1",{id:"数字系统设计",tabindex:"-1"},[e("a",{class:"header-anchor",href:"#数字系统设计","aria-hidden":"true"},"#"),t(" 数字系统设计")],-1),c=e("p",null,[t("我校课程官方名称：数字系统设计，与 "),e("em",null,"数字系统设计实践"),t(" 算是两门课，成绩不互通。")],-1),p={href:"https://www.bilibili.com/video/BV1av411p7j2",target:"_blank",rel:"noopener noreferrer"},u=e("p",null,"数系算是简单的一门课了，网课总计 33h，开个 3 倍速，跳过非重点也就 9h，绝对的速通（x",-1),_={href:"https://github.com/lxl66566/my-college-files/tree/main/%E4%BF%A1%E6%81%AF%E7%A7%91%E5%AD%A6%E4%B8%8E%E5%B7%A5%E7%A8%8B%E5%AD%A6%E9%99%A2/%E6%95%B0%E5%AD%97%E7%B3%BB%E7%BB%9F%E8%AE%BE%E8%AE%A1",target:"_blank",rel:"noopener noreferrer"},x=h('<h2 id="逻辑运算" tabindex="-1"><a class="header-anchor" href="#逻辑运算" aria-hidden="true">#</a> 逻辑运算</h2><h3 id="运算率" tabindex="-1"><a class="header-anchor" href="#运算率" aria-hidden="true">#</a> 运算率</h3><p>满足完整的分配率：</p><ul><li>A(B+C) = AB + AC</li><li><strong>A+BC = (A+B)(A+C)</strong></li><li>消去律（附加律）：AB + ¬AC <s>+ BC</s> = AB + ¬AC</li><li>反演规则与对偶规则：<em>对偶</em>变量保持不变，<em>反演</em>变。</li></ul><h3 id="其他概念" tabindex="-1"><a class="header-anchor" href="#其他概念" aria-hidden="true">#</a> 其他概念</h3><p>最小项是与项的子集，如 AB，最大项反之</p><h3 id="卡诺图" tabindex="-1"><a class="header-anchor" href="#卡诺图" aria-hidden="true">#</a> 卡诺图</h3><p>注意无关项的影响 - 复习</p><h2 id="组合逻辑电路" tabindex="-1"><a class="header-anchor" href="#组合逻辑电路" aria-hidden="true">#</a> 组合逻辑电路</h2><ul><li>全加器：S = A^B^C , C = (A^B)C + AB</li><li>编码器：输入 2^n 端口，输出 n 端口，同时只能有一个端口输入。相当于输入端口号转二进制</li><li>译码器：反编码；74138</li></ul><blockquote><p>需要掌握译码器的扩充，实现逻辑函数</p></blockquote><ul><li>多路选择器（MUX）</li><li>分配器（DEMUX）：逆选择器</li></ul><h3 id="竞争与冒险" tabindex="-1"><a class="header-anchor" href="#竞争与冒险" aria-hidden="true">#</a> 竞争与冒险</h3><p>当两个卡诺圈相切 / 出现 X+¬X | X*¬X 时可能会发生冒险</p><p>解决：</p><ol><li>增加冗余项</li><li>增加延时（RC滤波器）</li><li>加使能脉冲</li></ol><h2 id="触发器-flip-flop" tabindex="-1"><a class="header-anchor" href="#触发器-flip-flop" aria-hidden="true">#</a> 触发器（Flip Flop）</h2><p>有的触发器有 static 异步信号的输入。比时钟信号优先。</p><ul><li><p>基本 RS 触发器（<strong>Reset &amp; Set</strong>），两个与非门组成，交叉反馈。三个状态：置数，复位，保持。（+不允许）</p><ul><li>均为 0 则保持。不可均为 1.</li><li>不允许状态也可能有确定的输出，仅在 00 -&gt; 11 时，有不确定输出。</li></ul></li><li><p>钟控：加了控制信号 CP。CP=1：工作，CP=0：保持。</p><ul><li>钟控 D 触发器（Delay, 寄存器）：R===¬S, S=D, Q_n+1 = D</li><li>钟控 T 触发器（Toggle）：Q_n+1 = T ^ Q_n，T=0 Hold, T=1 Revert</li><li>JK 触发器，T 触发器拆输入。功能最多。Q_n+1 = J¬Q_n + ¬KQ_n</li></ul><table><thead><tr><th style="text-align:center;">J</th><th style="text-align:center;">K</th><th style="text-align:center;">Q_n+1</th></tr></thead><tbody><tr><td style="text-align:center;">0</td><td style="text-align:center;">0</td><td style="text-align:center;">Q_n</td></tr><tr><td style="text-align:center;">0</td><td style="text-align:center;">1</td><td style="text-align:center;">0</td></tr><tr><td style="text-align:center;">1</td><td style="text-align:center;">0</td><td style="text-align:center;">1</td></tr><tr><td style="text-align:center;">1</td><td style="text-align:center;">1</td><td style="text-align:center;">¬Q_n</td></tr></tbody></table></li></ul><h2 id="时序电路" tabindex="-1"><a class="header-anchor" href="#时序电路" aria-hidden="true">#</a> 时序电路</h2><h3 id="分类" tabindex="-1"><a class="header-anchor" href="#分类" aria-hidden="true">#</a> 分类</h3><ul><li>同步与异步</li><li>Mealy &amp; Moore. Mealy: Z=F(X,Q); Moore: Z=F(Q)</li></ul><h3 id="分析" tabindex="-1"><a class="header-anchor" href="#分析" aria-hidden="true">#</a> 分析</h3><p>...</p><h3 id="设计" tabindex="-1"><a class="header-anchor" href="#设计" aria-hidden="true">#</a> 设计</h3><p>原始状态图/表 -&gt; 化简 -&gt; 二进制状态表 ---触发器选择--&gt; 输出/激励方程（次态卡诺图） -&gt; 电路图</p><p>如果使用 JK 触发器设计，需要把卡诺图分为两部分，卡诺圈不能跨越隔开的部分。</p><h4 id="简化" tabindex="-1"><a class="header-anchor" href="#简化" aria-hidden="true">#</a> 简化</h4><p>输出相等，次态相等 | 交错 | 隐含，则可以进行状态合并。</p><h3 id="常见集成时序电路" tabindex="-1"><a class="header-anchor" href="#常见集成时序电路" aria-hidden="true">#</a> 常见集成时序电路</h3><ul><li>74161： 4 位 2 进制计数器，异步清零，同步置数</li><li>74LS194：移位器，可以实现串-并转换，环形计数等</li></ul><h2 id="ad-转换" tabindex="-1"><a class="header-anchor" href="#ad-转换" aria-hidden="true">#</a> AD 转换</h2><h3 id="d-a转换" tabindex="-1"><a class="header-anchor" href="#d-a转换" aria-hidden="true">#</a> D/A转换</h3><ul><li>权电阻型：反馈电阻 R_f = R / 2，（四位）输出 Vo = -V_REF * D_4 / 2^4</li><li>倒T型：反馈电阻 R_f = R</li><li>权电流型</li></ul><h2 id="ttl-门电路" tabindex="-1"><a class="header-anchor" href="#ttl-门电路" aria-hidden="true">#</a> TTL 门电路</h2>',35),f={href:"https://zhidao.baidu.com/question/326534526354970805.html",target:"_blank",rel:"noopener noreferrer"};function b(g,A){const a=r("ExternalLinkIcon");return n(),d("div",null,[s,c,e("p",null,[t("网课："),e("a",p,[t("西安电子科技大学（任爱峰老师主讲）——《数字电路与系统设计》"),l(a)])]),u,e("blockquote",null,[e("p",null,[t("20230628：考完了，这个笔记实际上用处不算太大，不如认真研究"),e("a",_,[t("考题"),l(a)]),t("的内容。但是看的网课还是有用的。")])]),x,e("p",null,[e("a",f,[t("输入端接大/小电阻的影响"),l(a)])])])}const m=i(o,[["render",b],["__file","dsp.html.vue"]]);export{m as default};
